DROP TABLE IF EXISTS `TrackLog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `TrackLog` (
  `id` int NOT NULL AUTO_INCREMENT,
  `trackId` int DEFAULT NULL,
  `userId` int DEFAULT NULL,
  `event` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `details` json DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`id`),
  KEY `TrackLog_trackId_idx` (`trackId`),
  KEY `TrackLog_createdAt_idx` (`createdAt`),
  CONSTRAINT `TrackLog_trackId_fkey` FOREIGN KEY (`trackId`) REFERENCES `Track` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2459 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
